class Solution:
    def __init__(self):
        self.dp: dict = {0:0, 1:1, 2:2, 3:3}

    def climbStairs(self, n: int) -> int:
        if n in self.dp:
            return self.dp[n]

        one = self.climbStairs(n -1)
        two = self.climbStairs(n - 2)

        self.dp[n] = one + two
        return self.dp[n]
